// 检查用户是否在黑名单中
function isUserBlacklisted(session, blacklistedUsers) {
    // 获取用户的openid
    const userOpenid = session.userId;
    // 检查用户是否在黑名单中
    return blacklistedUsers.includes(userOpenid);
}
// 回复黑名单用户
async function replyToBlacklistedUser(session, config) {
    try {
        const hasText = config.replyText && config.replyText.trim() !== '';
        const hasImage = config.replyImageUrl && config.replyImageUrl.trim() !== '';
        // 根据配置发送回复
        if (hasText && hasImage && config.sendBoth) {
            // 同时发送文本和图片
            await session.send(config.replyText);
            await session.send(`<image url="${config.replyImageUrl}"/>`);
        }
        else if (hasText) {
            // 只发送文本
            await session.send(config.replyText);
        }
        else if (hasImage) {
            // 只发送图片
            await session.send(`<image url="${config.replyImageUrl}"/>`);
        }
        // 记录日志
        session.app.logger('blacklist').info(`已拦截黑名单用户 ${session.userId} 的消息`);
    }
    catch (error) {
        // 错误处理
        session.app.logger('blacklist').error(`回复黑名单用户时出错: ${error}`);
    }
}
